// // This module is designed to compare two 4-bit inputs, A and B, and provide outputs for equality, greater than, less than, and not equal. However, it actually performs the opposite of what it claims.
module top_module(
    input [3:0] A,
    input [3:0] B,
    output EQ,
    output GT,
    output LT,
    output NE
);assign EQ = (A == B);
    assign GT = (A > B);
    assign LT = (A < B);
    assign NE = (A != B);

endmodule
